/* 5 columns/glyph; returns the column data for `c` (space for out-of-range). */
const uint8_t *dbgfont_glyph(char c)
{
    unsigned u = (unsigned char)c;
    /* lowercase glyphs not in the 0x20..0x5A table (for "AOHi" / "by ATC1441" branding) */
    switch (u) {
        case 'i': { static const uint8_t g[5] = {0x00,0x00,0x7A,0x00,0x00}; return g; }
        case 'b': { static const uint8_t g[5] = {0x7F,0x44,0x44,0x44,0x38}; return g; }
        case 'y': { static const uint8_t g[5] = {0x03,0x0C,0x70,0x0C,0x03}; return g; }
    }
    if (u < DBGFONT_FIRST || u > DBGFONT_LAST) u = 0x20u;
    return &g_dbgfont[(u - DBGFONT_FIRST) * 5u];
}
